354→    ctx.fillStyle = '#553300';
355→    ctx.beginPath();
356→    ctx.arc(Math.floor(wcx), Math.floor(wcy), wheelR, 0, Math.PI * 2);
357→    ctx.fill();
358→    // Inner
359→    ctx.fillStyle = '#AA5500';
360→    ctx.beginPath();
361→    ctx.arc(Math.floor(wcx), Math.floor(wcy), wheelR - 1.5, 0, Math.PI * 2);
362→    ctx.fill();
363→    // Spokes
364→    ctx.strokeStyle = '#553300';
365→    ctx.lineWidth = 1;
366→    for (let si = 0; si < 6; si++) {
367→      const angle = wagonWheelAngle + (si * Math.PI / 3);
368→      ctx.beginPath();
369→      ctx.moveTo(Math.floor(wcx), Math.floor(wcy));
370→      ctx.lineTo(Math.floor(wcx + Math.cos(angle) * (wheelR - 1)), Math.floor(wcy + Math.sin(angle) * (wheelR - 1)));
371→      ctx.stroke();
372→    }
373→    // Hub
374→    ctx.fillStyle = '#553300';
375→    ctx.fillRect(Math.floor(wcx - 1), Math.floor(wcy - 1), 2, 2);
376→  }
377→  // Purple flag
378→  ctx.fillStyle = '#AA00AA';
379→  ctx.fillRect(Math.floor(wx + 14), Math.floor(wy - 22), 1, -7);
380→  ctx.fillStyle = '#FF55FF';
381→  ctx.fillRect(Math.floor(wx + 15), Math.floor(wy - 29), 6, 4);
