}

function renderWinScreen() {
  var survivors = partyHealth.filter(function(h) { return h > 0; }).length;
  var pctScore = totalQuestions > 0 ? Math.round((score / totalQuestions) * 100) : 100;

  var conceptNames = ['Gateway Control Plane', 'Channel Plugins', 'Route Resolution', 'Session Persistence'];

  var masteryHtml = '';
  var weakestName = '';
  var weakestHp = 999;
  for (var i = 0; i < conceptNames.length; i++) {
    var hp = partyHealth[i];
    var maxHp = TRAIL_DATA.partyMembers[i].maxHealth;
    var stars, color;
    if (hp <= 0) {
      stars = '<span style="color:#555555">\u2606\u2606\u2606 (died)</span>';
      color = '#555555';
    } else {
      stars = '';
      for (var s = 0; s < hp; s++) stars += '\u2605';
      for (var s2 = 0; s2 < maxHp - hp; s2++) stars += '\u2606';
      color = '#FFFF55';
    }
    if (hp < weakestHp) { weakestHp = hp; weakestName = conceptNames[i]; }
    masteryHtml += '<div style="color:' + color + ';">    ' + conceptNames[i] + '  ' + stars + '</div>';
  }

  var tip = weakestHp < TRAIL_DATA.partyMembers[0].maxHealth ? '"Study up on ' + weakestName + '!"' : '"Perfect understanding!"';

  setTextPanel(
    '<div style="padding:8px 16px;">' +
    '<div style="color:#FFFF55; text-align:center; font-size:16px;">\u2605 YOU MADE IT TO RESPONSE FRONTIER! \u2605</div>' +
    '<div style="margin-top:10px; color:#AAAAAA;">' +
    '<div>  Framework:    <span style="color:#55FFFF;">OpenClaw (The Gateway Trail)</span></div>' +
    '<div>  Survivors:    <span style="color:#55FF55;">' + survivors + '/' + partyHealth.length + '</span></div>' +
    '<div>  Quiz Score:   <span style="color:#FFFF55;">' + score + '/' + totalQuestions + ' (' + pctScore + '%)</span></div>' +
    '<div>  Best Streak:  <span style="color:#FF55FF;">' + bestStreak + '</span></div>' +
    '<div>  Hints Used:   <span style="color:#AAAAAA;">' + hintsUsed + '</span></div>' +
    '</div>' +
    '<div style="margin-top:10px; color:#FFFF55;">  Concept Mastery:</div>' +
    '<div>' + masteryHtml + '</div>' +
    '<div style="margin-top:10px; color:#55FF55; text-align:center;">' + tip + '</div>' +
    '<div style="margin-top:14px; text-align:center;" class="blink">Press SPACE BAR to play again</div>' +
    '</div>'
  );
